PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?commentator ?commentatorLabel
WHERE {
  wd:Q56037086 wdt:P1777 wd:Q3143 .
  wd:Q56037086 wdt:P8859 ?commentator .
  SERVICE wikidata:label { bd:serviceParam wikibase:language "en". }
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?commentator ?commentatorLabel
WHERE {
  wd:Q56037086 wdt:P8859 ?commentator.
  SERVICE wikidata:label { bd:serviceParam wikibase:language "en". }
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT DISTINCT ?commentator ?commentatorLabel
WHERE {
  ?broadcast wdt:P273 wd:Q461786;
             wdt:P912 wd:Q51368;
             wdt:P8859 ?commentator.
  ?commentator rdfs:label ?commentatorLabel.
  FILTER(LANG(?commentatorLabel) = 'en')
}

