PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?broadcast ?broadcastLabel
WHERE {
  ?broadcast rdfs:label ?broadcastLabel.
  FILTER (CONTAINS(LCASE(?broadcastLabel), 'nbc olympic') && LANG(?broadcastLabel) = 'en')
}
